mapper.select:
Select m.m_id,m.lng,m.lat,m.remark,m.l_id,m.d_id,m.s_id,m.a_id,l.l_name,d.d_name,s.s_name,a.a_name
from markers m,languages l,dialects d,subdialects s,accents a
where m.l_id=l.l_id and m.d_id=d.d_id and m.s_id=s.s_id and
m.a_id=a.a_id and l.l_name=#{language}
and d.d_name=#{dialect}
and s.s_name=#{subdialect}
and a.a_name=#{accent}
